/**
 * Notification model — types and interfaces for the notification system.
 *
 * Architecture: All notifications flow through the EventBus. Domain events
 * (order:created, user:created, etc.) are handled by the NotificationService,
 * which constructs NotificationPayloads and delegates to registered adapters.
 */

/**
 * Supported notification channels. Each channel has a corresponding
 * NotificationAdapter implementation.
 */
export type NotificationChannel = 'email' | 'webhook' | 'sms' | 'in-app';

/**
 * Categories of notifications for routing and preference management.
 */
export type NotificationType =
  | 'order-confirmation'
  | 'order-status-update'
  | 'welcome'
  | 'account-update';

/**
 * Priority levels for notifications. Adapters may use this to determine
 * delivery urgency (e.g., high-priority skips batching).
 */
export type NotificationPriority = 'low' | 'normal' | 'high';

/**
 * The payload passed to notification adapters for delivery.
 */
export interface NotificationPayload {
  /** Unique notification ID. */
  id: string;
  /** Notification category for routing. */
  type: NotificationType;
  /** Target channels for this notification. */
  channels: NotificationChannel[];
  /** Delivery priority. */
  priority: NotificationPriority;
  /** Recipient identifier (email, user ID, etc. — adapters interpret this). */
  recipient: string;
  /** Notification subject/title. */
  subject: string;
  /** Notification body content. */
  body: string;
  /** Optional structured metadata for adapter-specific rendering. */
  metadata?: Record<string, unknown>;
  /** When the notification was created. */
  createdAt: Date;
}

/**
 * Record of a sent notification, including delivery result.
 */
export interface NotificationRecord extends NotificationPayload {
  /** Which channel delivered this notification. */
  deliveredVia: NotificationChannel;
  /** Whether delivery succeeded. */
  success: boolean;
  /** Error message if delivery failed. */
  error?: string;
  /** When delivery was attempted. */
  deliveredAt: Date;
}

/**
 * NotificationAdapter interface — the contract all notification delivery
 * channels must implement.
 *
 * Constraint: All adapters MUST implement this interface. The NotificationService
 * delegates delivery to registered adapters based on the notification's channels.
 *
 * To add a new channel:
 * 1. Add the channel name to NotificationChannel in src/models/notification.ts
 * 2. Create an adapter class implementing NotificationAdapter
 * 3. Register it with NotificationService.registerAdapter()
 */

import type { NotificationChannel, NotificationPayload } from '../models/notification.js';

/**
 * Result of a notification delivery attempt.
 */
export interface DeliveryResult {
  /** Whether the delivery succeeded. */
  success: boolean;
  /** Error message if delivery failed. */
  error?: string;
}

/**
 * Interface that all notification channel adapters must implement.
 */
export interface NotificationAdapter {
  /** The channel this adapter handles. */
  readonly channel: NotificationChannel;

  /**
   * Send a notification through this channel.
   * Must not throw — return a DeliveryResult with success: false on failure.
   */
  send(payload: NotificationPayload): Promise<DeliveryResult>;
}

/**
 * Email notification adapter — delivers notifications via email.
 *
 * This is a stub implementation that logs emails in-memory. Replace the
 * send() internals with a real email provider (SendGrid, SES, etc.) for
 * production use.
 */

import type { NotificationPayload } from '../models/notification.js';
import type { NotificationAdapter, DeliveryResult } from './notification.adapter.js';
import { Logger } from '../utils/logger.js';

/**
 * Structure of an email as captured by this adapter.
 */
export interface EmailMessage {
  to: string;
  subject: string;
  body: string;
  sentAt: Date;
}

export class EmailNotificationAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  private logger = new Logger('EmailAdapter');
  private sentEmails: EmailMessage[] = [];

  /**
   * Send a notification as an email.
   */
  async send(payload: NotificationPayload): Promise<DeliveryResult> {
    try {
      const email: EmailMessage = {
        to: payload.recipient,
        subject: payload.subject,
        body: payload.body,
        sentAt: new Date(),
      };

      // In production, this would call an email provider API.
      this.sentEmails.push(email);
      this.logger.info(`Email sent to ${payload.recipient}: ${payload.subject}`);

      return { success: true };
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Unknown error';
      this.logger.error(`Failed to send email to ${payload.recipient}: ${message}`);
      return { success: false, error: message };
    }
  }

  /**
   * Get all sent emails. Useful for testing.
   */
  getSentEmails(): EmailMessage[] {
    return [...this.sentEmails];
  }

  /**
   * Clear sent emails. Useful for testing.
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

/**
 * Notification service — handles sending notifications in response to
 * domain events via the EventBus.
 *
 * Architecture:
 * - ALL notifications are triggered by EventBus events (no direct calls).
 * - Delivery is delegated to registered NotificationAdapter implementations.
 * - New channels are added by implementing NotificationAdapter and calling
 *   registerAdapter(). No modification to this service is needed.
 * - New event types are handled by adding a subscriber in registerHandlers().
 *
 * Constraints:
 * - All notifications must go through EventBus.emit() — services must NOT
 *   call NotificationService methods directly.
 * - All adapters must implement the NotificationAdapter interface.
 * - Adapter failures are logged but do not block event processing.
 *
 * Depends on:
 * - EventBus (event system) for receiving domain events
 * - NotificationAdapter implementations for delivery
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import type { NotificationAdapter, DeliveryResult } from '../adapters/notification.adapter.js';
import type {
  NotificationChannel,
  NotificationPayload,
  NotificationRecord,
  NotificationType,
  NotificationPriority,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private adapters: Map<NotificationChannel, NotificationAdapter> = new Map();
  private records: NotificationRecord[] = [];

  constructor(private eventBus: EventBus) {
    this.registerHandlers();
  }

  /**
   * Register a notification adapter for a delivery channel.
   * Only one adapter per channel — later registrations replace earlier ones.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.adapters.set(adapter.channel, adapter);
    this.logger.info(`Registered adapter for channel: ${adapter.channel}`);
  }

  /**
   * Subscribe to domain events that trigger notifications.
   * Add new event subscriptions here as the system grows.
   */
  private registerHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      return this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      return this.handleOrderStatusChanged(event);
    });
  }

  /**
   * Handle order created event — send confirmation to user.
   */
  private async handleOrderCreated(event: OrderCreatedEvent): Promise<void> {
    this.logger.info(`Sending order confirmation for order ${event.order.id}`);

    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    await this.sendNotification({
      type: 'order-confirmation',
      channels: ['email'],
      priority: 'high',
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
      metadata: { orderId: event.order.id, userId: event.user.id },
    });
  }

  /**
   * Handle order status change — notify user of update.
   */
  private async handleOrderStatusChanged(event: OrderStatusChangedEvent): Promise<void> {
    this.logger.info(
      `Sending status update for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    await this.sendNotification({
      type: 'order-status-update',
      channels: ['email'],
      priority: 'normal',
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
      metadata: {
        orderId: event.order.id,
        previousStatus: event.previousStatus,
        newStatus: event.newStatus,
      },
    });
  }

  /**
   * Build a payload and deliver it through all specified channels.
   */
  private async sendNotification(params: {
    type: NotificationType;
    channels: NotificationChannel[];
    priority: NotificationPriority;
    recipient: string;
    subject: string;
    body: string;
    metadata?: Record<string, unknown>;
  }): Promise<void> {
    const payload: NotificationPayload = {
      id: generateNotificationId(),
      type: params.type,
      channels: params.channels,
      priority: params.priority,
      recipient: params.recipient,
      subject: params.subject,
      body: params.body,
      metadata: params.metadata,
      createdAt: new Date(),
    };

    for (const channel of payload.channels) {
      const adapter = this.adapters.get(channel);
      let result: DeliveryResult;

      if (!adapter) {
        this.logger.warn(`No adapter registered for channel: ${channel}`);
        result = { success: false, error: `No adapter for channel: ${channel}` };
      } else {
        result = await adapter.send(payload);
      }

      const record: NotificationRecord = {
        ...payload,
        deliveredVia: channel,
        success: result.success,
        error: result.error,
        deliveredAt: new Date(),
      };
      this.records.push(record);

      if (result.success) {
        this.logger.info(`Notification ${payload.id} delivered via ${channel}`);
      } else {
        this.logger.error(
          `Notification ${payload.id} failed via ${channel}: ${result.error}`,
        );
      }
    }
  }

  /**
   * Get all notification records.
   */
  getNotifications(): NotificationRecord[] {
    return [...this.records];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): NotificationRecord[] {
    return this.records.filter((n) => n.recipient === recipient);
  }

  /**
   * Get the count of notification records.
   */
  getNotificationCount(): number {
    return this.records.length;
  }

  /**
   * Clear all notification records (useful for testing).
   */
  clearNotifications(): void {
    this.records = [];
  }
}

